/**
 * Checks if array Y is a cyclic permutation of array X.
 * Assumes |X| = |Y| = k.
 * This uses string concatenation and substring search, achieving O(k) complexity 
 * due to efficient string searching algorithms in modern JavaScript engines.
 */
function isCyclicPermutation(X, Y) {
    const k = X.length;
    if (k === 0) return true;

    // Use a delimiter robust against the input values (1 to 10^5).
    const DELIMITER = ',';

    // Convert to delimited strings
    const strX = X.join(DELIMITER);
    const strY = Y.join(DELIMITER);

    // Concatenate X with itself (string representation)
    // A cyclic permutation of X must appear as a substring of X + X.
    // We insert a delimiter between the two copies to ensure boundaries are respected when searching for strY.
    const strXDoubled = strX + DELIMITER + strX;

    // Check if strY is a substring of strXDoubled
    return strXDoubled.includes(strY);
}

/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;

    // 1. Calculate S (sorted nums)
    const S = [...nums].sort((a, b) => a - b);

    // 2. Find all divisors k of n
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let totalSum = 0;

    // 3. Check each divisor k
    for (const k of divisors) {
        let isKSortable = true;

        // Iterate through blocks i = 0 to n/k - 1
        const m = n / k;
        for (let i = 0; i < m; i++) {
            const start = i * k;

            // Block Bi from original nums
            // Slice creates a shallow copy of the array segment
            const Bi = nums.slice(start, start + k);

            // Target block Bi' from sorted array S
            const BiPrime = S.slice(start, start + k);

            // Check if BiPrime is a cyclic permutation of Bi
            if (!isCyclicPermutation(Bi, BiPrime)) {
                isKSortable = false;
                break;
            }
        }

        if (isKSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

