        }
    }

    // 2. Cyclic shift check (O(k) using string matching)
    // We must use a robust delimiter since nums[i] <= 10^5.
    // A character not possible in standard number representations might be best, 
    // but since we are using standard JS string conversion, ',' is fine if we are careful.
    const DELIMITER = ',';

